// Integration test for GET /api/best-window — verifies the endpoint returns a
// valid calmest-window payload for real coordinates (Mediterranean off Barcelona).
async function testBestWindowEndpoint() {
  const res = await fetch('http://localhost:3001/api/best-window?lat=41.35&lon=2.17');
  assertEquals(res.status, 200, 'Best window should return 200');

  const data = await res.json();

  // Position/timezone echoed back
  assert(typeof data.latitude === 'number', 'Should include latitude');
  assert(typeof data.longitude === 'number', 'Should include longitude');
  assert(typeof data.timezone === 'string', 'Should include timezone');

  // The window object and its fields
  const w = data.window;
  assert(w && typeof w === 'object', 'Response should contain a window object');
  assert(typeof w.startIndex === 'number', 'window.startIndex should be a number');
  assert(typeof w.start === 'number', 'window.start should be a number');
  assert(typeof w.end === 'number', 'window.end should be a number');
  assert(typeof w.startTime === 'string', 'window.startTime should be a string');
  assert(typeof w.endTime === 'string', 'window.endTime should be a string');
  assert(typeof w.avgWind === 'number', 'window.avgWind should be a number');
  assert(typeof w.avgGust === 'number', 'window.avgGust should be a number');
  assert(typeof w.combinedScore === 'number', 'window.combinedScore should be a number');

  // The combined score should equal avgWind + avgGust (within rounding tolerance)
  assert(Math.abs(w.combinedScore - (w.avgWind + w.avgGust)) <= 0.1, 'combinedScore should match avgWind + avgGust');

  // Exactly 3 hours (default window size) with expected fields
  assert(Array.isArray(w.hours), 'window.hours should be an array');
  assertEquals(w.hours.length, 3, 'window should contain 3 hours by default');
  const h = w.hours[0];
  assert(typeof h.time === 'string', 'hour should have a time');
  assert(typeof h.windSpeed === 'number', 'hour should have windSpeed');
  assert(typeof h.windGusts === 'number', 'hour should have windGusts');

  // A human-readable reason string
  assert(typeof w.reason === 'string' && w.reason.length > 0, 'window.reason should be a non-empty string');
}
